INSERT INTO chains (name, entity, data, step_count, crack_count) VALUES ('antimicrobial-susceptibility', 'Antimicrobial Susceptibility', '{"entity":"Antimicrobial Susceptibility","steps":[{"claim":"MIC measured in Mueller-Hinton Broth predicts clinical outcome","level":"signal","convergence":"converged","measurements":[{"method":"Broth microdilution","value":"MIC in μg/mL","year":1940,"lab":"Standard (CLSI)"}],"depends":[45],"challengeCost":"Global standard for 80+ years","complexityLevel":2},{"claim":"Clinical outcomes diverge from susceptibility predictions (90-60 rule)","level":"measurement","convergence":"divergent","measurements":[{"method":"Susceptible → success","value":"~90% response","year":2011,"lab":"Doern/JCMI"},{"method":"Resistant → failure","value":"~60% still respond","year":2011,"lab":"Doern/JCMI"},{"method":"Physiological media MIC","value":"~15% cross breakpoints","year":2023,"lab":"Multiple"}],"depends":[45],"challengeCost":"Antimicrobial susceptibility is relational to host environment","complexityLevel":3,"sigmaTension":4}]}', 2, 1);
INSERT INTO chains (name, entity, data, step_count, crack_count) VALUES ('biology-as-level', 'Biology as Level', '{"entity":"Biology as Level","steps":[{"claim":"CRISPR knockout phenotypes cannot be predicted from protein structure alone","level":"signal","convergence":"converged","measurements":[{"method":"Systematic zebrafish KO screen","value":"~80% show no morpholino phenotype","year":2015,"lab":"Stainier"},{"method":"DepMap essentiality","value":"context-dependent across cell lines","year":2023,"lab":"Broad"}],"depends":[],"challengeCost":"Predict all KO phenotypes from chemistry","complexityLevel":3},{"claim":"Biological assays produce measurements with no chemical equivalent","level":"measurement","convergence":"converged","measurements":[{"method":"Clinical trial Phase III","value":"efficacy in patient population","year":2025,"lab":"Multiple"},{"method":"Fitness assay","value":"reproductive success rate","year":2020,"lab":"Multiple"},{"method":"Ecological survey","value":"species abundance","year":2020,"lab":"Multiple"}],"depends":[47,45],"challengeCost":"Derive clinical trial outcomes from reaction kinetics alone","complexityLevel":3},{"claim":"Biology has irreducible cracks: KO≠KD, 90-60 rule, 90% drug failure, biopsy discordance","level":"pattern","convergence":"converged","measurements":[{"method":"Cross-method survey","value":"4+ independent pathological gaps","year":2026,"lab":"This simulator"}],"depends":[52],"challengeCost":"Resolve all biology cracks from chemistry-level models","complexityLevel":3},{"claim":"Selection pressure (α<1) is measurable in biology but not definable in chemistry","level":"model","convergence":"tension","measurements":[{"method":"Assembly index + copy number","value":"MA≥15 → biotic","year":2021,"lab":"Marshall/Cronin"},{"method":"Fitness decoupling","value":"collective vs particle fitness","year":2003,"lab":"Michod"}],"depends":[],"challengeCost":"MA≥15 threshold contested (Hazen minerals); fitness decoupling debated (Bourrat)","complexityLevel":3,"sigmaTension":2.5},{"claim":"Living systems are closed to efficient causation (Rosen)","level":"hypothesis","convergence":"single","measurements":[{"method":"(M,R) systems","value":"category-theoretic proof of non-simulability","year":1991,"lab":"Rosen"},{"method":"Louie extension","value":"relational biology formalism","year":2009,"lab":"Louie"}],"depends":[],"challengeCost":"Build a simulator that fully captures an organism — if you can, Rosen is wrong","complexityLevel":3}]}', 5, 1);
INSERT INTO chains (name, entity, data, step_count, crack_count) VALUES ('biopsy-concordance', 'Biopsy Concordance', '{"entity":"Biopsy Concordance","steps":[{"claim":"Tissue biopsy detects somatic mutations in solid tumors","level":"signal","convergence":"converged","measurements":[{"method":"Targeted NGS panel","value":"actionable mutations detected","year":2015,"lab":"Multiple"}],"depends":[],"challengeCost":"Standard oncology","complexityLevel":3},{"claim":"Liquid biopsy (ctDNA) detects mutations non-invasively","level":"signal","convergence":"converged","measurements":[{"method":"cfDNA NGS","value":"mutations detected in blood","year":2016,"lab":"Multiple"}],"depends":[],"challengeCost":"Standard oncology","complexityLevel":3},{"claim":"Tissue and liquid biopsy concordance is only ~49%","level":"measurement","convergence":"divergent","measurements":[{"method":"ROME trial tissue+liquid","value":"49.2% concordance, N=1794","year":2026,"lab":"Vasseur et al."},{"method":"Lung adenocarcinoma progression","value":"~40% concordance at progression","year":2023,"lab":"Multiple"},{"method":"RCC multi-region sampling","value":"63-69% mutations missed by single biopsy","year":2020,"lab":"TRACERx"}],"depends":[],"challengeCost":"Tumor is genuinely heterogeneous — not a measurement error","complexityLevel":3,"sigmaTension":5},{"claim":"Tumor mutation profile is relational: depends on where and how you measure","level":"pattern","convergence":"divergent","measurements":[],"depends":[],"challengeCost":"Show heterogeneity is artifact not biology","complexityLevel":3,"sigmaTension":5}]}', 4, 2);
INSERT INTO chains (name, entity, data, step_count, crack_count) VALUES ('computation', 'Computation', '{"entity":"Computation","steps":[{"claim":"Bit erasure dissipates heat in physical substrate","level":"signal","convergence":"converged","measurements":[{"method":"Colloidal particle in double-well","value":"heat ≥ k_BT ln 2","year":2012,"lab":"Bérut/ENS Lyon (Nature)"},{"method":"Nanomagnetic bit flip","value":"0.026 eV at 300K (44% above bound)","year":2016,"lab":"Hong/Berkeley (Sci Adv)"},{"method":"Molecular magnets at 1K","value":"Landauer confirmed quantum regime","year":2018,"lab":"Gaudenzi (Nat Phys)"}],"depends":[],"challengeCost":"Three independent labs, three substrates. All confirm.","complexityLevel":0},{"claim":"Min energy/bit = k_BT ln 2; max speed = 4E/h; max bits = 2πRE/ℏc","level":"measurement","convergence":"converged","measurements":[{"method":"Landauer bound","value":"k_BT ln 2 = 2.87×10⁻²¹ J at 300K","year":1961,"lab":"Landauer/IBM"},{"method":"Margolus-Levitin","value":"6×10³³ ops/s/J","year":1998,"lab":"Margolus & Levitin"},{"method":"Bekenstein bound","value":"S ≤ 2πRE/ℏc","year":1981,"lab":"Bekenstein"}],"depends":[30,31,27],"challengeCost":"Violating thermodynamics, uncertainty, or black hole entropy","complexityLevel":0},{"claim":"Computation is a physical process with mass, time, and entropy","level":"pattern","convergence":"converged","measurements":[{"method":"Ultimate laptop","value":"1kg → 10⁵¹ ops/s, 10³¹ bits","year":2000,"lab":"Lloyd (Nature)"},{"method":"BH complexity","value":"BH = fastest computer per mass","year":2016,"lab":"Brown et al. (PRL)"}],"depends":[32,33,34],"challengeCost":"Finding a computation that violates all three bounds","complexityLevel":0},{"claim":"Physics = possible/impossible transformations (constructor theory)","level":"model","convergence":"converged","measurements":[{"method":"CT of information","value":"Info laws from physics alone","year":2015,"lab":"Deutsch & Marletto"},{"method":"CT of time","value":"Time emerges from constructors","year":2025,"lab":"Deutsch & Marletto"}],"depends":[],"challengeCost":"Alternative framework deriving information laws from physics","complexityLevel":0},{"claim":"Universe IS a self-consistent bounded computation (it from bit)","level":"hypothesis","convergence":"single","measurements":[{"method":"It from bit","value":"reality = apparatus-elicited bits","year":1989,"lab":"Wheeler"},{"method":"Self-model limit","value":"sub-system cannot out-compute whole","year":2026,"lab":"This simulator"}],"depends":[],"challengeCost":"Demonstrating a physical process that is NOT computational","complexityLevel":0}]}', 5, 0);
INSERT INTO chains (name, entity, data, step_count, crack_count) VALUES ('cosmic-dipole', 'Cosmic Dipole', '{"entity":"Cosmic Dipole","steps":[{"claim":"CMB dipole: ΔT = 3362.08 ± 0.99 μK, v = 369.82 km/s toward (l,b)=(264°,48°)","level":"signal","convergence":"converged","measurements":[{"method":"Planck HFI dipole","value":"3362.08 ± 0.99 μK","year":2020,"lab":"Planck"}],"depends":[],"challengeCost":"Overturn 30+ years of CMB measurement","complexityLevel":0},{"claim":"Matter dipole exceeds kinematic prediction by 2–4× across independent surveys","level":"measurement","convergence":"divergent","measurements":[{"method":"CatWISE2020 quasars (frequentist)","value":"D=0.01554, ratio=2.2×, 4.9σ","year":2021,"lab":"Secrest et al."},{"method":"CatWISE2020 quasars (Bayesian)","value":"D=(19±2)×10⁻³, ratio=2.7×, 5.7σ","year":2023,"lab":"Dam, Lewis & Brewer"},{"method":"NVSS+RACS radio dipole","value":"ratio≈3×, 4.8σ","year":2023,"lab":"Wagenveld et al."},{"method":"LoTSS+NVSS+RACS radio","value":"ratio=3.67±0.49, 5.4σ","year":2025,"lab":"Böhme et al."},{"method":"CatWISE revised (clustering)","value":"3.3–3.6σ after correction","year":2025,"lab":"Bashir et al."}],"depends":[37],"challengeCost":"Violation of cosmological principle; CMB dipole partly non-kinematic","complexityLevel":0,"sigmaTension":5.4},{"claim":"Large-scale isotropy is violated: matter distribution has anisotropic component","level":"pattern","convergence":"divergent","measurements":[],"depends":[38,39],"challengeCost":"Abandon FLRW isotropy assumption; superhorizon perturbations or tilted universe","complexityLevel":0,"sigmaTension":5.4}]}', 3, 2);
INSERT INTO chains (name, entity, data, step_count, crack_count) VALUES ('dark-matter', 'Dark Matter', '{"entity":"Dark Matter","steps":[{"claim":"Stars orbit faster than luminous mass predicts","level":"signal","convergence":"converged","measurements":[{"method":"Hα Doppler","value":"flat curves in M31","year":1970,"lab":"Rubin & Ford"},{"method":"SPARC database","value":"175 galaxies","year":2016,"lab":"Lelli/McGaugh"}],"depends":[18],"challengeCost":"Doppler wrong","complexityLevel":0},{"claim":"Mass separated from baryons in cluster collisions","level":"measurement","convergence":"converged","measurements":[{"method":"Weak lensing + X-ray","value":"8σ offset","year":2006,"lab":"Clowe/Bullet"}],"depends":[19],"challengeCost":"Lensing theory wrong","complexityLevel":0},{"claim":"Invisible gravitating substance exists (~5× visible)","level":"pattern","convergence":"converged","measurements":[{"method":"Rotation curves","value":"85-99% invisible","year":2025,"lab":"Multiple"},{"method":"CMB 3rd peak","value":"non-baryonic matter needed","year":2018,"lab":"Planck"},{"method":"Structure formation","value":"cold DM required","year":2020,"lab":"SDSS/DES"}],"depends":[20],"challengeCost":"Modified gravity fitting ALL four independent probes","complexityLevel":0},{"claim":"DM is a WIMP or similar particle","level":"hypothesis","convergence":"divergent","measurements":[{"method":"LZ","value":"NULL: σ<2.2×10⁻⁴⁸ cm²","year":2025,"lab":"Sanford"},{"method":"XENONnT","value":"NULL","year":2025,"lab":"LNGS"},{"method":"PandaX-4T","value":"NULL","year":2024,"lab":"Jinping"}],"depends":[],"challengeCost":"Already failing: 40 years, zero detections","complexityLevel":0,"sigmaTension":0}]}', 4, 1);
INSERT INTO chains (name, entity, data, step_count, crack_count) VALUES ('drug-binding-affinity', 'Drug Binding Affinity', '{"entity":"Drug Binding Affinity","steps":[{"claim":"Imatinib inhibits BCR-ABL kinase in crystal structure","level":"signal","convergence":"converged","measurements":[{"method":"X-ray crystallography","value":"DFG-out binding, Kd~37nM","year":2001,"lab":"Schindler et al."}],"depends":[44],"challengeCost":"Crystal structure wrong","complexityLevel":2},{"claim":"In-vitro and clinical efficacy initially converge","level":"measurement","convergence":"converged","measurements":[{"method":"SPR in vitro","value":"Kd = 37 nM","year":2002,"lab":"Novartis"},{"method":"IRIS Phase III","value":"95% hematologic remission CML","year":2003,"lab":"Druker et al."}],"depends":[44,45],"challengeCost":"Clinical trial wrong","complexityLevel":3},{"claim":"T315I gatekeeper mutation abolishes binding — single point mutation","level":"measurement","convergence":"converged","measurements":[{"method":"Kinase assay","value":"IC50 > 10 μM (>250× resistance)","year":2004,"lab":"Multiple"},{"method":"Clinical relapse","value":"~20% of resistant CML","year":2006,"lab":"MDACC"}],"depends":[44,46],"challengeCost":"Alternative resistance mechanism","complexityLevel":3},{"claim":"Binding model revised 4× since 1894","level":"pattern","convergence":"tension","measurements":[{"method":"AlphaFold-designed molecules","value":"5-15% hit rate","year":2024,"lab":"Multiple"}],"depends":[44,45,46],"challengeCost":"Build a binding model that predicts resistance mutations","complexityLevel":2,"sigmaTension":3}]}', 4, 1);
INSERT INTO chains (name, entity, data, step_count, crack_count) VALUES ('electron', 'Electron', '{"entity":"Electron","steps":[{"claim":"Cathode rays deflected by E and B fields","level":"signal","convergence":"converged","measurements":[{"method":"CRT","value":"deflection","year":1897,"lab":"Thomson"}],"depends":[],"challengeCost":"Replicated in every CRT for 100 years","complexityLevel":0},{"claim":"e/m = 1.759×10¹¹ C/kg, e = 1.602×10⁻¹⁹ C","level":"measurement","convergence":"converged","measurements":[{"method":"Cathode ray","value":"e/m = 1.759×10¹¹","year":1897,"lab":"Thomson"},{"method":"Oil drop","value":"e = 1.592×10⁻¹⁹ C","year":1909,"lab":"Millikan"},{"method":"Penning trap","value":"e/m to 0.005 ppt","year":2023,"lab":"Northwestern"}],"depends":[1],"challengeCost":"Lorentz force wrong","complexityLevel":0},{"claim":"\"Electron\" = universal pattern of e/m + charge + spin-½","level":"pattern","convergence":"converged","measurements":[{"method":"Global","value":"Same in every lab","year":2025,"lab":"Universal"}],"depends":[3,4],"challengeCost":"Clustering is coincidental","complexityLevel":0},{"claim":"Fundamental fermion in Standard Model (QED)","level":"model","convergence":"converged","measurements":[{"method":"QED g-2","value":"agrees to 0.13 ppt","year":2023,"lab":"Fan/Gabrielse"}],"depends":[11],"challengeCost":"Match QED 10⁻¹² precision","complexityLevel":0}]}', 4, 0);
INSERT INTO chains (name, entity, data, step_count, crack_count) VALUES ('expanding-universe', 'Expanding Universe', '{"entity":"Expanding Universe","steps":[{"claim":"Galaxy spectra shifted to longer wavelengths","level":"signal","convergence":"converged","measurements":[{"method":"Spectrometry","value":"41 redshifts","year":1925,"lab":"Slipher"},{"method":"Modern surveys","value":"millions","year":2025,"lab":"SDSS/DESI"}],"depends":[],"challengeCost":"Every spectrometer miscalibrated identically","complexityLevel":0},{"claim":"z correlates with distance (Hubble law)","level":"measurement","convergence":"converged","measurements":[{"method":"Cepheids + z","value":"v = H₀d","year":1929,"lab":"Hubble"}],"depends":[23],"challengeCost":"Distance ladder wrong","complexityLevel":0},{"claim":"Expansion rate H₀","level":"measurement","convergence":"divergent","measurements":[{"method":"CMB + ΛCDM","value":"67.4 ± 0.5","year":2018,"lab":"Planck"},{"method":"TRGB (JWST)","value":"69.96 ± 1.05 ± 1.12","year":2025,"lab":"Freedman"},{"method":"Cepheids+SNe","value":"73.04 ± 1.04","year":2022,"lab":"Riess SH0ES"},{"method":"Cepheids+SNe JWST","value":"73.49 ± 0.93","year":2025,"lab":"Riess SH0ES"}],"depends":[24,25],"challengeCost":"JWST rules out Cepheid crowding at 8σ. Unknown systematic.","complexityLevel":0,"sigmaTension":5.8},{"claim":"Space itself expands (FLRW metric)","level":"model","convergence":"converged","measurements":[{"method":"GR + cosmo principle","value":"predicts CMB+BBN+structure","year":1922,"lab":"Friedmann"}],"depends":[27],"challengeCost":"Alternative explaining CMB + nucleosynthesis + structure","complexityLevel":0},{"claim":"Dark energy drives accelerating expansion","level":"hypothesis","convergence":"tension","measurements":[{"method":"SNe Ia","value":"acceleration at z<1","year":1998,"lab":"Perlmutter/Riess"},{"method":"DESI BAO","value":"w₀=-0.69, wₐ=-1.13 (not ΛCDM)","year":2025,"lab":"DESI DR2"}],"depends":[28,29],"challengeCost":"SNe Ia evolve with z","complexityLevel":0,"sigmaTension":3.5}]}', 5, 2);
INSERT INTO chains (name, entity, data, step_count, crack_count) VALUES ('knockout-vs-knockdown', 'Knockout vs Knockdown', '{"entity":"Knockout vs Knockdown","steps":[{"claim":"Gene deletion (CRISPR) produces complete protein absence","level":"signal","convergence":"converged","measurements":[{"method":"CRISPR frameshift","value":"protein absent (Western blot)","year":2013,"lab":"Multiple"}],"depends":[],"challengeCost":"Replicated across thousands of genes","complexityLevel":3},{"claim":"Gene knockdown (RNAi/morpholino) reduces expression toward zero but not absent","level":"signal","convergence":"converged","measurements":[{"method":"Morpholino","value":"80-95% reduction","year":2000,"lab":"Multiple"},{"method":"siRNA","value":"70-90% reduction","year":2001,"lab":"Multiple"}],"depends":[],"challengeCost":"Standard molecular biology","complexityLevel":3},{"claim":"Knockout and knockdown phenotypes frequently disagree","level":"measurement","convergence":"divergent","measurements":[{"method":"EGFL7 KO","value":"normal vasculature (compensated)","year":2015,"lab":"Rossi/Stainier"},{"method":"EGFL7 KD","value":"severe vascular defects","year":2015,"lab":"Rossi/Stainier"},{"method":"Systematic zebrafish","value":"~80% KO show no KD phenotype","year":2015,"lab":"Stainier lab"}],"depends":[48],"challengeCost":"Abandon assumption that gene = function = phenotype","complexityLevel":3,"sigmaTension":4},{"claim":"NITC: mutant mRNA triggers transcriptional compensation of paralogs","level":"pattern","convergence":"converged","measurements":[{"method":"RNA-seq after KO","value":"paralog upregulation in KO not KD","year":2019,"lab":"El-Brolosy/Stainier"}],"depends":[50,51],"challengeCost":"Find KO-KD discrepancy without NITC","complexityLevel":3},{"claim":"Gene function is relational: depends on measurement method, not intrinsic to sequence","level":"hypothesis","convergence":"single","measurements":[],"depends":[52],"challengeCost":"Show all KO-KD discrepancies are NITC artifacts","complexityLevel":3}]}', 5, 1);
INSERT INTO chains (name, entity, data, step_count, crack_count) VALUES ('missing-heritability', 'Missing Heritability', '{"entity":"Missing Heritability","steps":[{"claim":"Twin studies estimate height heritability at ~80%","level":"signal","convergence":"converged","measurements":[{"method":"MZ vs DZ twin correlation","value":"h² ≈ 0.80","year":1990,"lab":"Multiple"}],"depends":[],"challengeCost":"Twin study methodology for 100+ years","complexityLevel":3},{"claim":"GWAS explains much less variance than twin studies predict","level":"measurement","convergence":"tension","measurements":[{"method":"Early GWAS (common SNPs)","value":"h² ≈ 0.05 (height)","year":2008,"lab":"GIANT"},{"method":"WGS (common+rare)","value":"h² ≈ 0.68 common + 0.20 rare = 0.88","year":2025,"lab":"Young/Nature"},{"method":"Behavioral (IQ) GWAS","value":"h² ≈ 0.10 vs twin 0.50-0.70","year":2024,"lab":"Multiple"}],"depends":[],"challengeCost":"Height closing (WGS); behavioral gap remains enormous","complexityLevel":3,"sigmaTension":3},{"claim":"Twin studies may systematically overestimate h² by ~2× for behavioral traits","level":"pattern","convergence":"tension","measurements":[],"depends":[],"challengeCost":"The crack is in the twin methodology, not the molecular data","complexityLevel":3,"sigmaTension":2.5}]}', 3, 2);
INSERT INTO chains (name, entity, data, step_count, crack_count) VALUES ('neutron', 'Neutron', '{"entity":"Neutron","steps":[{"claim":"Neutral penetrating radiation ejects protons from paraffin","level":"signal","convergence":"converged","measurements":[{"method":"Be+α→n","value":"neutral radiation detected","year":1932,"lab":"Chadwick"}],"depends":[],"challengeCost":"Replicated immediately","complexityLevel":0},{"claim":"Mass = 1.6749×10⁻²⁷ kg (neutral)","level":"measurement","convergence":"converged","measurements":[{"method":"Reaction kinematics","value":"m = 1.67493×10⁻²⁷ kg","year":2020,"lab":"CODATA"}],"depends":[12],"challengeCost":"Energy conservation wrong","complexityLevel":0},{"claim":"Neutron lifetime τ","level":"measurement","convergence":"divergent","measurements":[{"method":"UCN bottle (count survivors)","value":"τ = 878.4 ± 0.5 s","year":2021,"lab":"UCNτ / LANL"},{"method":"Beam (count decay protons)","value":"τ = 887.7 ± 2.2 s","year":2013,"lab":"NIST"},{"method":"Beam (count decay electrons)","value":"τ = 877.2 ± 1.7 s","year":2024,"lab":"J-PARC"}],"depends":[13,14],"challengeCost":"Decades of systematic error searches found nothing. UCNProBe will test both simultaneously.","complexityLevel":0,"sigmaTension":4.5},{"claim":"\"Neutron\" = particle that β-decays to p + e⁻ + ν̄ₑ","level":"pattern","convergence":"converged","measurements":[{"method":"Decay product ID","value":"p + e⁻ + ν̄ₑ confirmed","year":1957,"lab":"Wu"}],"depends":[15],"challengeCost":"Products misidentified","complexityLevel":0},{"claim":"Contains quarks (udd), QCD model","level":"model","convergence":"converged","measurements":[{"method":"DIS + magnetic moment","value":"consistent with udd","year":1968,"lab":"SLAC"}],"depends":[],"challengeCost":"Same as proton quark model","complexityLevel":0},{"claim":"~1% of neutrons decay into dark sector particles","level":"hypothesis","convergence":"single","measurements":[],"depends":[16],"challengeCost":"Speculative. J-PARC complicates the picture.","complexityLevel":0}]}', 6, 1);
INSERT INTO chains (name, entity, data, step_count, crack_count) VALUES ('proton', 'Proton', '{"entity":"Proton","steps":[{"claim":"Positive particles with specific e/m in B fields","level":"signal","convergence":"converged","measurements":[{"method":"Canal rays","value":"positive deflection","year":1886,"lab":"Goldstein"}],"depends":[],"challengeCost":"Replicated 130+ years","complexityLevel":0},{"claim":"Mass and charge measured to 10⁻¹¹ precision","level":"measurement","convergence":"converged","measurements":[{"method":"Penning trap","value":"m=1.67262×10⁻²⁷ kg","year":2020,"lab":"CODATA"}],"depends":[2],"challengeCost":"Penning trap physics wrong","complexityLevel":0},{"claim":"Proton charge radius","level":"measurement","convergence":"tension","measurements":[{"method":"Electron scattering","value":"r = 0.877 ± 0.007 fm","year":2000,"lab":"Pre-2010 CODATA"},{"method":"Muonic hydrogen","value":"r = 0.84184 ± 0.00067 fm","year":2010,"lab":"CREMA/PSI"},{"method":"e-scattering PRad","value":"r = 0.831 ± 0.014 fm","year":2019,"lab":"JLab"},{"method":"H spectroscopy 2S-4P","value":"r = 0.8335 ± 0.0095 fm","year":2019,"lab":"MPQ Garching"}],"depends":[6,7],"challengeCost":"Converging toward smaller value but not fully settled","complexityLevel":0,"sigmaTension":3.5},{"claim":"\"Proton\" = stable particle, universal properties, lifetime > 10³⁴ yr","level":"pattern","convergence":"converged","measurements":[{"method":"Global","value":"Universal","year":2025,"lab":"Universal"}],"depends":[5,4],"challengeCost":"Pattern coincidental","complexityLevel":0},{"claim":"Contains quarks (uud) bound by gluons (QCD)","level":"model","convergence":"converged","measurements":[{"method":"DIS","value":"point-like scatterers","year":1968,"lab":"SLAC"},{"method":"3-jet events","value":"gluon radiation","year":1979,"lab":"DESY"},{"method":"Lattice QCD","value":"hadron masses to 1-2%","year":2008,"lab":"BMW"},{"method":"EMC effect","value":"quark distribution changes in nuclei","year":1983,"lab":"CERN"}],"depends":[],"challengeCost":"Explain DIS + jets + spectrum without quarks. No free quark ever found.","complexityLevel":0}]}', 5, 1);
INSERT INTO chains (name, entity, data, step_count, crack_count) VALUES ('s8-structure-growth', 'S₈ Structure Growth', '{"entity":"S₈ Structure Growth","steps":[{"claim":"CMB predicts S₈ = 0.832 ± 0.013 from primary anisotropies","level":"signal","convergence":"converged","measurements":[{"method":"Planck 2018 TT,TE,EE+lensing ΛCDM","value":"S₈ = 0.832 ± 0.013","year":2020,"lab":"Planck"},{"method":"Planck+ACT DR6+SPT-3G combined","value":"S₈ = 0.836 +0.012/−0.013","year":2026,"lab":"Pantos & Perivolaropoulos"}],"depends":[],"challengeCost":"Overturn Planck CMB analysis","complexityLevel":0},{"claim":"Late-universe weak lensing measures lower S₈, but surveys disagree with each other","level":"measurement","convergence":"tension","measurements":[{"method":"KiDS-1000 cosmic shear","value":"S₈ = 0.759 ± 0.023, 3.0σ","year":2021,"lab":"KiDS"},{"method":"KiDS Legacy cosmic shear","value":"S₈ = 0.815 +0.016/−0.021, 0.73σ","year":2025,"lab":"KiDS"},{"method":"DES Y3 3×2pt","value":"S₈ = 0.776 ± 0.017, ~2σ","year":2022,"lab":"DES"},{"method":"DES Y6 3×2pt","value":"S₈ = 0.789 ± 0.012, 2.4–2.8σ","year":2026,"lab":"DES"},{"method":"HSC Y3 recalibrated","value":"S₈ = 0.805 ± 0.018, ~1.4σ","year":2025,"lab":"HSC+DESI"},{"method":"ACT DR6 CMB lensing","value":"S₈ = 0.840 ± 0.028","year":2024,"lab":"ACT"}],"depends":[40,41],"challengeCost":"Photo-z systematics dominate; KiDS resolved after recalibration, DES persists","complexityLevel":0,"sigmaTension":2.8},{"claim":"Structure growth may be suppressed relative to ΛCDM prediction","level":"pattern","convergence":"tension","measurements":[],"depends":[42,43],"challengeCost":"If real: DM-neutrino interactions, decaying DM, or modified gravity needed","complexityLevel":0,"sigmaTension":2.4}]}', 3, 2);
